def validate_api_key(f):
    """Decorator to validate API key authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get("Authorization", "")
        if not auth_header.startswith("Bearer "):
            logger.warning("Missing or malformed Authorization header")
            return jsonify({"error": "Unauthorized"}), 401

        provided_key = auth_header[7:]
        # Use constant-time comparison to prevent timing attacks
        if not hmac.compare_digest(provided_key.encode(), API_SECRET_KEY.encode()):
            logger.warning("Invalid API key provided")
            return jsonify({"error": "Unauthorized"}), 401

        return f(*args, **kwargs)
    return decorated


def validate_index_name(index_name):
    """Validate index name against allowlist."""
    if not isinstance(index_name, str):
        return False
    # Must be in allowlist
    if index_name not in ALLOWED_INDICES:
        return False
    # Additional safety: no special characters that could cause injection
    if not re.match(r'^[a-z][a-z0-9_-]*$', index_name):
        return False
    return True


def validate_field_name(field_name, allowed_fields):
    """Validate field name against the template's allowed fields."""
    if not isinstance(field_name, str):
        return False
    if field_name not in allowed_fields:
        return False
    return True


def validate_numeric_param(value):
    """Validate that a parameter is a safe numeric value."""
    if isinstance(value, bool):
        return False
    if isinstance(value, (int, float)):
        # Prevent infinity/NaN
        if isinstance(value, float) and (value != value or value == float('inf') or value == float('-inf')):
            return False
        return True
    return False


def sanitize_and_validate_params(script_template, user_params):
    """
    Validate user-provided parameters against the script template's allowed params.
    Returns sanitized params dict or raises ValueError.
    """
    if not isinstance(user_params, dict):
        raise ValueError("Parameters must be a dictionary")

    allowed_params = script_template["allowed_params"]
    allowed_fields = script_template.get("allowed_fields", set())
    sanitized = {}

    # Check that only allowed parameter names are provided
    for key in user_params:
        if key not in allowed_params:
            raise ValueError(f"Parameter '{key}' is not allowed for this script template")

    for param_name in allowed_params:
        if param_name not in user_params:
            raise ValueError(f"Required parameter '{param_name}' is missing")

        value = user_params[param_name]

        # If the parameter name contains "field", validate as a field name
        if "field" in param_name:
            if not validate_field_name(value, allowed_fields):
                raise ValueError(
                    f"Field '{value}' is not in the allowed fields list: {sorted(allowed_fields)}"
                )
            sanitized[param_name] = value
        else:
            # Numeric parameters
            if not validate_numeric_param(value):
                raise ValueError(f"Parameter '{param_name}' must be a numeric value")
            sanitized[param_name] = value

    return sanitized


